#include <stdio.h>
#include <stdlib.h>
#define MAX_N 100005
typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

Node* createNode(int val) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->val = val;
    node->left = NULL;
    node->right = NULL;
    return node;
}

void dfs(Node* node, int* xor_values, int* max_xor_values, int* current_xor) {
    if (node == NULL) return;
    *current_xor ^= node->val;
    xor_values[node->val] = *current_xor;
    max_xor_values[node->val] = *current_xor;
    dfs(node->left, xor_values, max_xor_values, current_xor);
    dfs(node->right, xor_values, max_xor_values, current_xor);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        Node* root = createNode(0);
        int* xor_values = (int*)malloc(N * sizeof(int));
        int* max_xor_values = (int*)malloc(N * sizeof(int));
        int current_xor = 0;
        dfs(root, xor_values, max_xor_values, &current_xor);
        for (int i = 0; i < N; i++) {
            printf("%d\n", max_xor_values[i]);
        }
        free(xor_values);
        free(max_xor_values);
    }
    return 0;
}

